import React, { useCallback, useEffect, useState } from 'react';
import { complaintService } from '../api/dashboardServices';
import '../styles/ecoflow-3d-theme.css';

function ComplaintsManagement() {
  const [loading, setLoading] = useState(true);
  const [complaints, setComplaints] = useState([]);
  const [selectedComplaint, setSelectedComplaint] = useState(null);
  const [filter, setFilter] = useState('open');
  const [newComment, setNewComment] = useState('');
  const [newStatus, setNewStatus] = useState('');

  const loadComplaints = useCallback(async () => {
    try {
      const data = await complaintService.getComplaints(filter !== 'all' ? filter : null);
      setComplaints(data);
    } catch (err) {
      console.error(err);
    } finally {
      setLoading(false);
    }
  }, [filter]);

  useEffect(() => {
    loadComplaints();
  }, [loadComplaints]);

  const handleStatusChange = async (complaintId, status, notes) => {
    try {
      await complaintService.updateComplaintStatus(complaintId, status, notes);
      loadComplaints();
      setSelectedComplaint(null);
    } catch (err) {
      console.error(err);
    }
  };

  const handleAddComment = async (complaintId) => {
    if (!newComment.trim()) return;
    try {
      await complaintService.addComment(complaintId, newComment);
      setNewComment('');
      loadComplaints();
    } catch (err) {
      console.error(err);
    }
  };

  const getStatusColor = (status) => {
    switch (status) {
      case 'open': return '#ff2244';
      case 'in_review': return '#ffd93d';
      case 'resolved': return '#38ef7d';
      case 'closed': return '#a0b0c0';
      default: return '#a0b0c0';
    }
  };

  const getStatusBadge = (status) => {
    switch (status) {
      case 'open': return 'critical';
      case 'in_review': return 'warning';
      case 'resolved': return 'success';
      case 'closed': return 'info';
      default: return 'info';
    }
  };

  const getPriorityColor = (priority) => {
    switch (priority) {
      case 'high': return '#ff2244';
      case 'medium': return '#ffd93d';
      case 'low': return '#38ef7d';
      default: return '#a0b0c0';
    }
  };

  return (
    <div className="page-header">
      <div>
        <h1 className="page-title">💬 Complaints Management</h1>
        <p className="page-subtitle">Citizen complaints workflow and resolution tracking</p>
      </div>

      <div className="page-content">
        {loading ? (
          <div className="spinner" style={{ margin: '40px auto' }}></div>
        ) : (
          <div className="grid grid-3">
            {/* Complaints List */}
            <div style={{ gridColumn: '1 / 2' }}>
              <div className="card">
                <div className="card-header">
                  <div className="card-title">Complaints</div>
                  <div className="badge badge-info">{complaints.length}</div>
                </div>

                {/* Filter Buttons */}
                <div style={{ display: 'flex', gap: '6px', marginBottom: '12px', flexWrap: 'wrap' }}>
                  {['all', 'open', 'in_review', 'resolved'].map(status => (
                    <button
                      key={status}
                      className={`btn btn-sm ${filter === status ? 'btn-accent' : 'btn-secondary'}`}
                      onClick={() => setFilter(status)}
                    >
                      {status.toUpperCase().replace('_', ' ')}
                    </button>
                  ))}
                </div>

                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', maxHeight: '600px', overflowY: 'auto' }}>
                  {complaints.map((complaint, idx) => (
                    <div
                      key={idx}
                      className="card interactive"
                      onClick={() => setSelectedComplaint(complaint)}
                      style={{
                        cursor: 'pointer',
                        borderColor: selectedComplaint?.id === complaint.id ? '#00ff88' : 'rgba(0, 255, 136, 0.1)',
                        background: selectedComplaint?.id === complaint.id 
                          ? 'rgba(0, 255, 136, 0.1)' 
                          : 'rgba(0, 0, 0, 0.2)',
                        borderLeftColor: getStatusColor(complaint.status),
                        borderLeftWidth: '3px'
                      }}
                    >
                      <div style={{ display: 'flex', gap: '8px', alignItems: 'start' }}>
                        <div style={{ fontSize: '16px' }}>📋</div>
                        <div style={{ flex: 1 }}>
                          <div style={{ fontWeight: '600', fontSize: '13px' }}>
                            {complaint.subject}
                          </div>
                          <div style={{ fontSize: '11px', color: '#a0b0c0', marginTop: '4px' }}>
                            ID: {complaint.id}
                          </div>
                          <div style={{ fontSize: '11px', color: '#a0b0c0' }}>
                            {new Date(complaint.created_at).toLocaleDateString()}
                          </div>
                        </div>
                        <span className={`badge badge-${getStatusBadge(complaint.status)}`} style={{ fontSize: '10px' }}>
                          {complaint.status.toUpperCase().replace('_', ' ')}
                        </span>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            </div>

            {/* Complaint Details */}
            {selectedComplaint && (
              <div style={{ gridColumn: '2 / 4' }}>
                <div className="card">
                  <div className="card-header">
                    <div>
                      <div className="card-title">{selectedComplaint.subject}</div>
                      <div className="card-subtitle">ID: {selectedComplaint.id}</div>
                    </div>
                    <button 
                      className="btn btn-secondary btn-sm"
                      onClick={() => setSelectedComplaint(null)}
                    >
                      ✕
                    </button>
                  </div>

                  {/* Complaint Info */}
                  <div className="grid grid-2">
                    <div style={{ padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase' }}>Status</div>
                      <div style={{ fontSize: '14px', fontWeight: '600', marginTop: '6px', color: getStatusColor(selectedComplaint.status) }}>
                        {selectedComplaint.status.toUpperCase().replace('_', ' ')}
                      </div>
                    </div>

                    <div style={{ padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase' }}>Priority</div>
                      <div style={{ fontSize: '14px', fontWeight: '600', marginTop: '6px', color: getPriorityColor(selectedComplaint.priority) }}>
                        {selectedComplaint.priority.toUpperCase()}
                      </div>
                    </div>

                    <div style={{ padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase' }}>Submitted By</div>
                      <div style={{ fontSize: '14px', fontWeight: '600', marginTop: '6px' }}>
                        {selectedComplaint.submitter_name}
                      </div>
                    </div>

                    <div style={{ padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                      <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase' }}>Date</div>
                      <div style={{ fontSize: '14px', fontWeight: '600', marginTop: '6px' }}>
                        {new Date(selectedComplaint.created_at).toLocaleDateString()}
                      </div>
                    </div>
                  </div>

                  {/* Complaint Description */}
                  <div style={{ marginTop: '16px', padding: '12px', background: 'rgba(0, 0, 0, 0.2)', borderRadius: '8px' }}>
                    <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase', marginBottom: '8px' }}>Description</div>
                    <div style={{ fontSize: '13px', color: '#d0d8e8', lineHeight: '1.6' }}>
                      {selectedComplaint.description}
                    </div>
                  </div>

                  {/* Comments Section */}
                  <div style={{ marginTop: '16px' }}>
                    <div style={{ fontSize: '11px', color: '#a0b0c0', textTransform: 'uppercase', marginBottom: '12px' }}>
                      Comments ({selectedComplaint.comments?.length || 0})
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '8px', maxHeight: '200px', overflowY: 'auto' }}>
                      {selectedComplaint.comments?.map((comment, idx) => (
                        <div key={idx} style={{ padding: '12px', background: 'rgba(0, 255, 136, 0.05)', borderRadius: '6px', borderLeft: '2px solid rgba(0, 255, 136, 0.3)' }}>
                          <div style={{ fontSize: '11px', color: '#a0b0c0' }}>
                            {comment.author} - {new Date(comment.created_at).toLocaleString()}
                          </div>
                          <div style={{ fontSize: '12px', marginTop: '4px', color: '#d0d8e8' }}>
                            {comment.text}
                          </div>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Add Comment */}
                  {selectedComplaint.status !== 'closed' && (
                    <div style={{ marginTop: '16px' }}>
                      <div className="input-group">
                        <label className="input-label">Add Comment</label>
                        <textarea
                          className="input-field"
                          placeholder="Type your comment or resolution notes..."
                          value={newComment}
                          onChange={(e) => setNewComment(e.target.value)}
                          style={{ minHeight: '80px', fontFamily: 'inherit' }}
                        />
                      </div>
                      <button 
                        className="btn btn-primary"
                        style={{ width: '100%', marginTop: '8px' }}
                        onClick={() => handleAddComment(selectedComplaint.id)}
                      >
                        💬 Add Comment
                      </button>
                    </div>
                  )}

                  {/* Change Status */}
                  {selectedComplaint.status !== 'closed' && (
                    <div style={{ marginTop: '16px', display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '8px' }}>
                      <select
                        className="select-field"
                        value={newStatus}
                        onChange={(e) => setNewStatus(e.target.value)}
                      >
                        <option value="">Change Status</option>
                        {['in_review', 'resolved', 'closed'].map(status => (
                          <option key={status} value={status}>
                            {status.toUpperCase().replace('_', ' ')}
                          </option>
                        ))}
                      </select>
                      <button 
                        className="btn btn-accent"
                        disabled={!newStatus}
                        onClick={() => {
                          handleStatusChange(selectedComplaint.id, newStatus, newComment);
                          setNewStatus('');
                          setNewComment('');
                        }}
                      >
                        ✓ Update
                      </button>
                    </div>
                  )}

                  {selectedComplaint.status === 'closed' && (
                    <div style={{ marginTop: '16px', padding: '12px', background: 'rgba(56, 239, 125, 0.1)', borderRadius: '8px', border: '1px solid rgba(56, 239, 125, 0.3)', textAlign: 'center' }}>
                      <div style={{ fontSize: '12px', color: '#38ef7d', fontWeight: '600' }}>✓ This complaint has been closed</div>
                    </div>
                  )}
                </div>
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

export default ComplaintsManagement;
